// Dashboard.js - Updated with Chart.js components
import React, { useState, useEffect, useRef } from 'react';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend,
  ArcElement
} from 'chart.js';
import { Bar, Line, Doughnut } from 'react-chartjs-2';
import './Dashboard.css';

// Register Chart.js components
ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Title,
  Tooltip,
  Legend,
  ArcElement
);

function Dashboard({ dashboardData }) {
  const [activeTab, setActiveTab] = useState('overview');
  const [chartData, setChartData] = useState(null);

  // Generate sample chart data when component mounts or data changes
  useEffect(() => {
    if (dashboardData) {
      generateChartData();
    }
  }, [dashboardData]);

  const generateChartData = () => {
    const apiData = dashboardData.individualResult || {};
    
    const data = {
      riskFactors: {
        labels: [
          'Days Since Last Order',
          'Satisfaction Score', 
          'Cashback Amount',
          'Tenure Duration',
          'Order Frequency',
          'Complaint History'
        ],
        datasets: [
          {
            label: 'Feature Importance',
            data: [0.32, 0.28, 0.15, 0.12, 0.08, 0.05],
            backgroundColor: [
              '#ef4444',
              '#f97316', 
              '#f59e0b',
              '#eab308',
              '#84cc16',
              '#10b981'
            ],
            borderColor: [
              '#dc2626',
              '#ea580c',
              '#d97706',
              '#ca8a04',
              '#65a30d',
              '#059669'
            ],
            borderWidth: 1,
          },
        ],
      },
      trendAnalysis: {
        labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May'],
        datasets: [
          {
            label: 'Churn Risk %',
            data: [25, 32, 45, 62, 79],
            borderColor: '#ef4444',
            backgroundColor: 'rgba(239, 68, 68, 0.1)',
            tension: 0.4,
            fill: true
          },
          {
            label: 'Satisfaction Score',
            data: [4.2, 3.8, 3.5, 3.2, 2.8],
            borderColor: '#3b82f6',
            backgroundColor: 'rgba(59, 130, 246, 0.1)',
            tension: 0.4,
            fill: true
          }
        ],
      },
      monthlyMetrics: {
        labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May'],
        datasets: [
          {
            label: 'Monthly Orders',
            data: [8, 6, 5, 4, 3],
            backgroundColor: 'rgba(16, 185, 129, 0.8)',
            borderColor: '#10b981',
            borderWidth: 1
          },
          {
            label: 'Cashback Used (%)',
            data: [85, 72, 65, 58, 45],
            backgroundColor: 'rgba(139, 92, 246, 0.8)',
            borderColor: '#8b5cf6',
            borderWidth: 1
          }
        ],
      },
      riskDistribution: {
        labels: ['Low Risk', 'Medium Risk', 'High Risk'],
        datasets: [
          {
            data: [25, 35, 40],
            backgroundColor: [
              '#10b981',
              '#f59e0b',
              '#ef4444'
            ],
            borderColor: [
              '#059669',
              '#d97706',
              '#dc2626'
            ],
            borderWidth: 2
          }
        ]
      }
    };
    
    setChartData(data);
  };

  // Chart options
  const barOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Feature Importance Analysis',
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        max: 0.4,
        ticks: {
          callback: function(value) {
            return (value * 100) + '%';
          }
        }
      }
    }
  };

  const lineOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Customer Behavior Trends',
      },
    },
    scales: {
      y: {
        beginAtZero: true,
      }
    }
  };

  const stackedBarOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Monthly Customer Metrics',
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        max: 100
      }
    }
  };

  const doughnutOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'bottom',
      },
      title: {
        display: true,
        text: 'Risk Level Distribution',
      },
    }
  };

  if (!dashboardData) {
    return (
      <div className="dashboard">
        <div className="dashboard-header">
          <h2>Churn Analysis Dashboard</h2>
        </div>
        <div className="dashboard-placeholder">
          <div className="placeholder-content">
            <span className="placeholder-icon">🔍</span>
            <h3>No Analysis Data Available</h3>
            <p>Run a customer analysis to view insights and predictions</p>
          </div>
        </div>
      </div>
    );
  }

  // Extract data from API response
  const apiData = dashboardData.individualResult || {};
  
  // Enhanced data with dynamic values from API
  const analysisData = {
    churnRisk: Math.round((apiData.probability || 0.792) * 1000) / 10,
    // ... rest of your existing analysis data
  };

  // Risk Factors Bar Chart Component
  const RiskFactorsChart = () => {
    if (!chartData) return <div className="chart-loading">Loading chart data...</div>;
    
    return (
      <div className="chart-card">
        <div className="chart-header">
          <h3>Key Churn Risk Factors</h3>
          <span className="chart-subtitle">Feature Importance (SHAP Values)</span>
        </div>
        <div className="chart-container">
          <Bar data={chartData.riskFactors} options={barOptions} />
        </div>
      </div>
    );
  };

  // Trend Analysis Line Chart Component
  const TrendAnalysisChart = () => {
    if (!chartData) return <div className="chart-loading">Loading chart data...</div>;
    
    return (
      <div className="chart-card">
        <div className="chart-header">
          <h3>Customer Behavior Trends</h3>
          <span className="chart-subtitle">5-Month Historical Analysis</span>
        </div>
        <div className="chart-container">
          <Line data={chartData.trendAnalysis} options={lineOptions} />
        </div>
      </div>
    );
  };

  // Monthly Metrics Bar Chart Component
  const MonthlyMetricsChart = () => {
    if (!chartData) return <div className="chart-loading">Loading chart data...</div>;
    
    return (
      <div className="chart-card">
        <div className="chart-header">
          <h3>Monthly Engagement Metrics</h3>
          <span className="chart-subtitle">Order & Cashback Patterns</span>
        </div>
        <div className="chart-container">
          <Bar data={chartData.monthlyMetrics} options={stackedBarOptions} />
        </div>
      </div>
    );
  };

  // Risk Distribution Doughnut Chart Component
  const RiskDistributionChart = () => {
    if (!chartData) return <div className="chart-loading">Loading chart data...</div>;
    
    return (
      <div className="chart-card">
        <div className="chart-header">
          <h3>Risk Level Distribution</h3>
          <span className="chart-subtitle">Customer Portfolio Overview</span>
        </div>
        <div className="chart-container">
          <Doughnut data={chartData.riskDistribution} options={doughnutOptions} />
        </div>
      </div>
    );
  };

  // Feature Impact Comparison
  const FeatureImpactComparison = () => {
    if (!chartData) return <div className="chart-loading">Loading chart data...</div>;
    
    const comparisonData = {
      labels: ['Current Customer', 'Benchmark'],
      datasets: [
        {
          label: 'Days Since Last Order',
          data: [apiData.customer_data?.DaySinceLastOrder || 25, 7],
          backgroundColor: 'rgba(239, 68, 68, 0.8)',
        },
        {
          label: 'Satisfaction Score',
          data: [apiData.customer_data?.SatisfactionScore || 2, 4.5],
          backgroundColor: 'rgba(59, 130, 246, 0.8)',
        },
        {
          label: 'Tenure (Months)',
          data: [apiData.customer_data?.Tenure || 3, 12],
          backgroundColor: 'rgba(16, 185, 129, 0.8)',
        }
      ]
    };

    const comparisonOptions = {
      responsive: true,
      plugins: {
        legend: {
          position: 'top',
        },
        title: {
          display: true,
          text: 'Current vs Benchmark Metrics',
        },
      },
      scales: {
        x: {
          stacked: true,
        },
        y: {
          stacked: true
        }
      }
    };

    return (
      <div className="chart-card">
        <div className="chart-header">
          <h3>Performance Comparison</h3>
          <span className="chart-subtitle">Current vs Ideal Benchmarks</span>
        </div>
        <div className="chart-container">
          <Bar data={comparisonData} options={comparisonOptions} />
        </div>
      </div>
    );
  };

  // Customer Retention Action Plan
  const RetentionActionPlan = () => (
    <div className="chart-card">
      <div className="chart-header">
        <h3>Customer Retention Action Plan</h3>
        <span className="chart-subtitle">Priority Actions for Risk Mitigation</span>
      </div>
      <div className="chart-content">
        <div className="action-plan">
          <div className="action-category immediate">
            <h4>🚨 Immediate Actions (Next 24-48 hours)</h4>
            <ul>
              <li>Personalized outreach from dedicated account manager</li>
              <li>Exclusive limited-time discount offer (25% off next purchase)</li>
              <li>Priority customer service hotline access</li>
            </ul>
          </div>
          
          <div className="action-category short-term">
            <h4>📅 Short-term Actions (Next 7 days)</h4>
            <ul>
              <li>Personalized product recommendations based on browsing history</li>
              <li>Loyalty program tier upgrade with enhanced benefits</li>
              <li>Customer satisfaction survey with incentive completion</li>
            </ul>
          </div>
          
          <div className="action-category long-term">
            <h4>🎯 Long-term Strategy (Next 30 days)</h4>
            <ul>
              <li>Regular personalized communication cadence</li>
              <li>Early access to new products and promotions</li>
              <li>Quarterly business review and value assessment</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );

  // Enhanced Overview Tab (your existing content)
  const renderOverview = () => (
    <div className="overview-tab-enhanced">
      {/* Your existing overview components */}
      <div className="overview-content">
        <p>Overview content goes here...</p>
      </div>
    </div>
  );

  // Detailed Analysis Tab with Charts
  const renderDetailedAnalysis = () => (
    <div className="detailed-analysis-tab">
      <div className="analysis-grid">
        <div className="analysis-column">
          <RiskFactorsChart />
          <MonthlyMetricsChart />
          <FeatureImpactComparison />
        </div>
        <div className="analysis-column">
          <TrendAnalysisChart />
          <RiskDistributionChart />
          <RetentionActionPlan />
        </div>
      </div>
    </div>
  );

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <div className="header-main">
          <h2>Churn Analysis Dashboard</h2>
        </div>
        <div className="header-actions">
          <button className="btn secondary">Export Report</button>
          <button className="btn primary">Save Analysis</button>
        </div>
      </div>

      <div className="dashboard-nav">
        <div className="nav-tabs">
          <button className={`nav-button ${activeTab === 'overview' ? 'active' : ''}`}
            onClick={() => setActiveTab('overview')}>
            Overview
          </button>
          <button className={`nav-button ${activeTab === 'detailed' ? 'active' : ''}`}
            onClick={() => setActiveTab('detailed')}>
            Detailed Analysis
          </button>
        </div>
      </div>

      <div className="tab-content">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'detailed' && renderDetailedAnalysis()}
      </div>
    </div>
  );
}

export default Dashboard;
